/* ─── TELECOM CANVAS OVERLAY ─────────────────────────────── */
function TelecomOverlay() {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    let raf = null;

    function resize() {
      canvas.width  = canvas.offsetWidth;
      canvas.height = canvas.offsetHeight;
    }
    resize();
    window.addEventListener("resize", resize);

    /* ── fiber routes with traveling pulses ── */
    const routes = [];
    function buildRoutes() {
      routes.length = 0;
      const W = canvas.width;
      const H = canvas.height;
      const ys = [H * 0.22, H * 0.38, H * 0.54, H * 0.70, H * 0.84];
      ys.forEach(function(y) {
        routes.push({ x1: W * 0.03, y1: y, x2: W * 0.97, y2: y, t: Math.random(), speed: 0.0012 + Math.random() * 0.001, alpha: 0.12 + Math.random() * 0.1 });
      });
      const xs = [W * 0.18, W * 0.45, W * 0.78];
      xs.forEach(function(x) {
        routes.push({ x1: x, y1: H * 0.04, x2: x, y2: H * 0.96, t: Math.random(), speed: 0.001 + Math.random() * 0.0008, alpha: 0.08 + Math.random() * 0.08 });
      });
    }
    buildRoutes();
    window.addEventListener("resize", buildRoutes);

    /* ── signal rings from towers ── */
    const rings = [];
    function buildRings() {
      rings.length = 0;
      const W = canvas.width;
      const H = canvas.height;
      var towerXs = [W * 0.18, W * 0.45, W * 0.78];
      towerXs.forEach(function(tx) {
        var cy = H * 0.83;
        [0, 1, 2].forEach(function(k) {
          rings.push({ x: tx, y: cy, r: k * 22, maxR: 70, speed: 0.45 });
        });
      });
    }
    buildRings();
    window.addEventListener("resize", buildRings);

    /* ── draw a tower ── */
    function drawTower(x, y, h) {
      ctx.strokeStyle = "rgba(56,217,255,0.38)";
      ctx.lineWidth = 1.2;
      ctx.beginPath(); ctx.moveTo(x, y); ctx.lineTo(x, y - h); ctx.stroke();
      var fracs = [0.3, 0.55, 0.78];
      fracs.forEach(function(f) {
        var ay = y - h * f;
        var w  = h * (1 - f) * 0.38;
        ctx.beginPath(); ctx.moveTo(x - w, ay); ctx.lineTo(x + w, ay); ctx.stroke();
        ctx.beginPath(); ctx.moveTo(x - w, ay); ctx.lineTo(x, ay - h * 0.07); ctx.stroke();
        ctx.beginPath(); ctx.moveTo(x + w, ay); ctx.lineTo(x, ay - h * 0.07); ctx.stroke();
      });
      ctx.beginPath(); ctx.moveTo(x - h * 0.22, y); ctx.lineTo(x + h * 0.22, y); ctx.stroke();
    }

    function draw() {
      canvas.width  = canvas.offsetWidth;
      canvas.height = canvas.offsetHeight;
      var W = canvas.width;
      var H = canvas.height;
      ctx.clearRect(0, 0, W, H);

      /* grid */
      ctx.strokeStyle = "rgba(56,217,255,0.035)";
      ctx.lineWidth = 0.6;
      for (var gx = 0; gx < W; gx += 80) {
        ctx.beginPath(); ctx.moveTo(gx, 0); ctx.lineTo(gx, H); ctx.stroke();
      }
      for (var gy = 0; gy < H; gy += 80) {
        ctx.beginPath(); ctx.moveTo(0, gy); ctx.lineTo(W, gy); ctx.stroke();
      }

      /* fiber route lines + pulses */
      routes.forEach(function(r) {
        ctx.beginPath();
        ctx.moveTo(r.x1, r.y1); ctx.lineTo(r.x2, r.y2);
        ctx.strokeStyle = "rgba(56,217,255," + r.alpha + ")";
        ctx.lineWidth = 0.7;
        ctx.stroke();

        r.t += r.speed;
        if (r.t > 1) r.t = 0;
        var px = r.x1 + (r.x2 - r.x1) * r.t;
        var py = r.y1 + (r.y2 - r.y1) * r.t;
        var grd = ctx.createRadialGradient(px, py, 0, px, py, 14);
        grd.addColorStop(0, "rgba(56,217,255,0.95)");
        grd.addColorStop(0.4, "rgba(56,217,255,0.3)");
        grd.addColorStop(1, "rgba(56,217,255,0)");
        ctx.beginPath(); ctx.arc(px, py, 14, 0, Math.PI * 2);
        ctx.fillStyle = grd; ctx.fill();
        ctx.beginPath(); ctx.arc(px, py, 2.5, 0, Math.PI * 2);
        ctx.fillStyle = "#fff"; ctx.fill();
      });

      /* towers */
      var towerData = [
        [W * 0.18, H * 0.93, H * 0.07],
        [W * 0.45, H * 0.96, H * 0.08],
        [W * 0.78, H * 0.91, H * 0.07],
      ];
      towerData.forEach(function(td) {
        drawTower(td[0], td[1], td[2]);
      });

      /* signal rings */
      rings.forEach(function(ring) {
        ring.r += ring.speed;
        if (ring.r > ring.maxR) ring.r = 0;
        var a = (1 - ring.r / ring.maxR) * 0.22;
        ctx.beginPath(); ctx.arc(ring.x, ring.y, ring.r, 0, Math.PI * 2);
        ctx.strokeStyle = "rgba(56,217,255," + a + ")";
        ctx.lineWidth = 1; ctx.stroke();
      });

      /* HUD corner brackets */
      var bOff = 28;
      var bLen = 18;
      ctx.strokeStyle = "rgba(56,217,255,0.45)";
      ctx.lineWidth = 1.5;
      /* top-left */
      ctx.beginPath(); ctx.moveTo(bOff + bLen, bOff); ctx.lineTo(bOff, bOff); ctx.lineTo(bOff, bOff + bLen); ctx.stroke();
      /* top-right */
      ctx.beginPath(); ctx.moveTo(W - bOff - bLen, bOff); ctx.lineTo(W - bOff, bOff); ctx.lineTo(W - bOff, bOff + bLen); ctx.stroke();
      /* bottom-left */
      ctx.beginPath(); ctx.moveTo(bOff + bLen, H - bOff); ctx.lineTo(bOff, H - bOff); ctx.lineTo(bOff, H - bOff - bLen); ctx.stroke();
      /* bottom-right */
      ctx.beginPath(); ctx.moveTo(W - bOff - bLen, H - bOff); ctx.lineTo(W - bOff, H - bOff); ctx.lineTo(W - bOff, H - bOff - bLen); ctx.stroke();

      /* HUD text */
      ctx.font = "bold 10px 'Outfit', monospace";
      ctx.fillStyle = "rgba(56,217,255,0.5)";
      ctx.fillText("TELECOM NETWORK ACTIVE", W - 212, 32);
      ctx.fillText("LAT 32.7767 N  LON 96.7970 W", W - 212, 48);

      raf = requestAnimationFrame(draw);
    }

    draw();

    return function() {
      if (raf) cancelAnimationFrame(raf);
      window.removeEventListener("resize", resize);
      window.removeEventListener("resize", buildRoutes);
      window.removeEventListener("resize", buildRings);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      style={{ position: "absolute", inset: 0, width: "100%", height: "100%", zIndex: 3, pointerEvents: "none" }}
    />
  );
}


/* ─── TECH LOGO WITH FALLBACK ────────────────────────────── */
function TechLogoImg({ src, alt, abbr, color, bg }) {
  var [failed, setFailed] = useState(false);
  var isLight = bg && (bg === "#f0f0f0" || bg.startsWith("#f") || bg.startsWith("#e"));
  if (failed || !src) {
    return (
      <span style={{
        fontFamily: "'Barlow Condensed', sans-serif",
        fontSize: abbr && abbr.length > 3 ? 12 : 16,
        fontWeight: 800, color: color, letterSpacing: 0.5,
        textAlign: "center", lineHeight: 1.1, padding: "0 4px",
      }}>{abbr}</span>
    );
  }
  return (
    /* eslint-disable-next-line @next/next/no-img-element */
    <img
      src={src} alt={alt}
      style={{ width: 58, height: 58, objectFit: "contain", padding: 4 }}
      onError={function() { setFailed(true); }}
    />
  );
}

/* ─── LOGO STRIP ─────────────────────────────────────────── */
function LogoStrip({ items, dark, fast }) {
  var doubled = items.concat(items);
  return (
    <div className="logo-strip-wrap" style={{ overflow: "hidden", position: "relative" }}>
      {/* fade edges */}
      <div style={{ position: "absolute", left: 0, top: 0, bottom: 0, width: 80, zIndex: 2, pointerEvents: "none",
        background: dark ? "linear-gradient(90deg,#010c22,transparent)" : "linear-gradient(90deg,#fff,transparent)" }} />
      <div style={{ position: "absolute", right: 0, top: 0, bottom: 0, width: 80, zIndex: 2, pointerEvents: "none",
        background: dark ? "linear-gradient(-90deg,#010c22,transparent)" : "linear-gradient(-90deg,#fff,transparent)" }} />

      <div style={{ display: "flex", animation: (fast ? "logoScroll 22s" : "logoScroll 32s") + " linear infinite", width: "max-content" }}>
        {doubled.map(function(item, i) {
          return (
            <div key={i} style={{ display: "flex", alignItems: "center", justifyContent: "center", padding: "0 44px", flexShrink: 0, height: 84 }}>
              {dark ? (
                /* dark bg: show logo on a white pill so it stays visible */
                <div style={{ background: "rgba(255,255,255,0.92)", borderRadius: 10, padding: "8px 18px", display: "flex", alignItems: "center", justifyContent: "center", height: 52, minWidth: 110, maxWidth: 150, transition: "all 0.3s" }}
                  onMouseEnter={function(e) { e.currentTarget.style.background = "#fff"; e.currentTarget.style.transform = "scale(1.06)"; }}
                  onMouseLeave={function(e) { e.currentTarget.style.background = "rgba(255,255,255,0.92)"; e.currentTarget.style.transform = "scale(1)"; }}>
                  {/* eslint-disable-next-line @next/next/no-img-element */}
                  <img src={item.logo} alt={item.name} style={{ height: 30, maxWidth: 120, objectFit: "contain" }} />
                </div>
              ) : (
                /* light bg: show logo with grayscale, color on hover */
                <div style={{ display: "flex", alignItems: "center", justifyContent: "center", padding: "6px 0", transition: "all 0.3s" }}>
                  {/* eslint-disable-next-line @next/next/no-img-element */}
                  <img
                    src={item.logo} alt={item.name}
                    style={{ height: 34, maxWidth: 130, objectFit: "contain", filter: "grayscale(1)", opacity: 0.5, transition: "all 0.3s" }}
                    onMouseEnter={function(e) { e.target.style.filter = "grayscale(0)"; e.target.style.opacity = "1"; e.target.style.transform = "scale(1.07)"; }}
                    onMouseLeave={function(e) { e.target.style.filter = "grayscale(1)"; e.target.style.opacity = "0.5"; e.target.style.transform = "scale(1)"; }}
                  />
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

/* ─── SERVICE MODAL ──────────────────────────────────────── */
function Modal({ s, onClose }) {
  useEffect(function() {
    function fn(e) { if (e.key === "Escape") onClose(); }
    document.addEventListener("keydown", fn);
    return function() { document.removeEventListener("keydown", fn); };
  }, [onClose]);

  return (
    <div
      onClick={onClose}
      style={{ position: "fixed", inset: 0, background: "rgba(5,15,42,0.78)", backdropFilter: "blur(8px)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center", padding: 24, animation: "fadeIn 0.2s ease" }}
    >
      <div
        onClick={function(e) { e.stopPropagation(); }}
        style={{ background: "#fff", borderRadius: 20, maxWidth: 660, width: "100%", overflow: "hidden", boxShadow: "0 40px 100px rgba(5,15,42,0.3)", animation: "slideUp 0.3s ease" }}
      >
        <div style={{ position: "relative", height: 260 }}>
          {/* eslint-disable-next-line @next/next/no-img-element */}
          <img src={s.img} alt={s.title} style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }} />
          <div style={{ position: "absolute", inset: 0, background: "linear-gradient(to top, rgba(5,15,42,0.92) 0%, transparent 50%)" }} />
          <div style={{ position: "absolute", bottom: 28, left: 32, right: 60 }}>
            <div style={{ fontSize: 11, color: "#38d9ff", letterSpacing: 3, textTransform: "uppercase", fontWeight: 700, marginBottom: 8 }}>{s.num}</div>
            <h2 style={{ fontFamily: "'Barlow Condensed', sans-serif", fontSize: 30, fontWeight: 800, color: "#fff", margin: 0 }}>{s.title}</h2>
          </div>
          <button onClick={onClose} style={{ position: "absolute", top: 18, right: 18, width: 38, height: 38, borderRadius: "50%", background: "rgba(255,255,255,0.15)", border: "1px solid rgba(255,255,255,0.25)", color: "#fff", fontSize: 22, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center" }}>
            ×
          </button>
        </div>
        <div style={{ padding: "32px 36px 40px" }}>
          <p style={{ fontSize: 16, lineHeight: 1.85, color: "#374569" }}>{s.full}</p>
          <button onClick={onClose} style={{ marginTop: 28, background: "#0055e9", color: "#fff", border: "none", padding: "13px 32px", borderRadius: 10, fontSize: 14, fontWeight: 600, cursor: "pointer", fontFamily: "'Outfit', sans-serif" }}>
            Close
          </button>
        </div>
      </div>
    </div>
  );
}

