  const [videoOk,     setVideoOk]     = useState(true);
  const [form,        setForm]        = useState({ first: "", last: "", email: "", subject: "", service: "", message: "" });
  const [sent,        setSent]        = useState(false);

  const techRef = useRef(null);
  const fttxRef = useRef(null);

  /* scroll listener */
  useEffect(function() {
    function fn() { setScrolled(window.scrollY > 60); }
    window.addEventListener("scroll", fn);
    return function() { window.removeEventListener("scroll", fn); };
  }, []);

  /* intersection observers */
  useEffect(function() {
    function makeObs(ref, setter) {
      var el = ref.current;
      if (!el) return null;
      var obs = new IntersectionObserver(function(entries) {
        if (entries[0].isIntersecting) setter(true);
      }, { threshold: 0.15 });
      obs.observe(el);
      return function() { obs.disconnect(); };
    }
    var c1 = makeObs(techRef, setVisibleTech);
    var c2 = makeObs(fttxRef, setVisibleFttx);
    return function() { if (c1) c1(); if (c2) c2(); };
  }, []);

  function go(id) {
    var el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: "smooth" });
  }
  function goTop() { window.scrollTo({ top: 0, behavior: "smooth" }); }

  const [sending, setSending] = useState(false);
  const [error,   setError]   = useState("");

